arguments.file_text:
@using System.Timers
@implements IDisposable
@inject INotificationService NotificationService

<span class="notification-badge" @onclick="HandleClick">
    @if (_unreadCount > 0)
    {
        <span class="badge">@_unreadCount</span>
    }
</span>

@code {
    [Parameter]
    public EventCallback OnClick { get; set; }

    private int _unreadCount;
    private Timer? _pollingTimer;

    protected override async Task OnInitializedAsync()
    {
        _unreadCount = await NotificationService.GetUnreadCountAsync();

        NotificationService.OnNotificationReceived += HandleNotificationReceived;

        _pollingTimer = new Timer(30_000);
        _pollingTimer.Elapsed += async (_, _) => await PollUnreadCountAsync();
        _pollingTimer.Start();
    }

    private void HandleNotificationReceived(Notification notification)
    {
        _unreadCount++;
        InvokeAsync(StateHasChanged);
    }

    private async Task PollUnreadCountAsync()
    {
        _unreadCount = await NotificationService.GetUnreadCountAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task HandleClick()
    {
        await OnClick.InvokeAsync();
    }

    public void Dispose()
    {
        NotificationService.OnNotificationReceived -= HandleNotificationReceived;

        if (_pollingTimer is not null)
        {
            _pollingTimer.Stop();
            _pollingTimer.Dispose();
            _pollingTimer = null;
        }
    }
}

